// // This is a 2-to-1 multiplexer that selects between inputs 'a' and 'b' based on 'sel'. When 'sel' is 0, 'out' is assigned the value of 'b', and when 'sel' is 1, 'out' is assigned the value of 'a'.
module top_module(
   input a,
   input b,
   input sel,
   output reg out
   );always @ (a, b, sel) begin
     case (sel)
       0: out = a;
       1: out = b;
     endcase
   end
endmodule
